## Unit Tests

```rust
#[cfg(test)]
mod tests {
    use super::*;
    use tracing::{info, debug};

    #[test]
    fn test_builder_default() {
        info!("Testing TlsConnectorBuilder default");
        let builder = TlsConnectorBuilder::new();
        // Should build (with warning about no root certs)
        let _connector = builder.build().unwrap();
    }

    #[test]
    fn test_builder_alpn_http() {
        info!("Testing ALPN HTTP configuration");
        let connector = TlsConnectorBuilder::new()
            .alpn_http()
            .build()
            .unwrap();

        assert_eq!(
            connector.config().alpn_protocols,
            vec![b"h2".to_vec(), b"http/1.1".to_vec()]
        );
    }

    #[test]
    fn test_builder_alpn_h2() {
        info!("Testing ALPN H2 configuration");
        let connector = TlsConnectorBuilder::new()
            .alpn_h2()
            .build()
            .unwrap();

        assert_eq!(
            connector.config().alpn_protocols,
            vec![b"h2".to_vec()]
        );
    }

    #[test]
    fn test_builder_custom_alpn() {
        info!("Testing custom ALPN protocols");
        let connector = TlsConnectorBuilder::new()
            .alpn_protocols(vec![b"grpc".to_vec()])
            .build()
            .unwrap();

        assert_eq!(
            connector.config().alpn_protocols,
            vec![b"grpc".to_vec()]
        );
    }

    #[test]
    fn test_builder_disable_sni() {
        info!("Testing SNI disable");
        let connector = TlsConnectorBuilder::new()
            .disable_sni()
            .build()
            .unwrap();

        assert!(!connector.config().enable_sni);
    }

    #[test]
    fn test_connector_clone() {
        info!("Testing TlsConnector clone is cheap");
        let connector = TlsConnectorBuilder::new()
            .build()
            .unwrap();

        let start = std::time::Instant::now();
        for _ in 0..10000 {
            let _clone = connector.clone();
        }
        let elapsed = start.elapsed();

        debug!(elapsed_us = elapsed.as_micros(), "10000 clones");
        // Should be very fast (Arc clone)
        assert!(elapsed.as_millis() < 100);
    }

    #[tokio::test]
    async fn test_connect_invalid_domain() {
        info!("Testing connect with invalid domain");
        let connector = TlsConnectorBuilder::new()
            .build()
            .unwrap();

        // Use a fake stream that will fail
        let stream = tokio::io::duplex(1024).0;

        let result = connector.connect("invalid domain with spaces", stream).await;
        assert!(result.is_err());

        if let Err(TlsError::InvalidDnsName(name)) = result {
            assert!(name.contains("invalid"));
        } else {
            panic!("Expected InvalidDnsName error");
        }
    }

    // Integration test - requires network
    #[tokio::test]
    #[ignore] // Run with --ignored for integration tests
    async fn test_connect_real_server() {
        info!("Testing real TLS connection to example.com");

        let connector = TlsConnectorBuilder::new()
            .with_webpki_roots()
            .alpn_http()
            .build()
            .unwrap();

        let stream = tokio::net::TcpStream::connect("example.com:443")
            .await
            .unwrap();

        let tls_stream = connector.connect("example.com", stream)
            .await
            .unwrap();

        debug!(
            version = ?tls_stream.protocol_version(),
            alpn = ?tls_stream.alpn_protocol(),
            "Connected to example.com"
        );

        assert!(tls_stream.protocol_version().is_some());
    }
}
